import{_ as i,o as a,c as l,ak as t}from"./chunks/framework.DkeEmzcj.js";const u=JSON.parse('{"title":"Android Changelog","description":"Release notes for the Punjab Educare Android app, listed in reverse chronological order.","frontmatter":{"title":"Android Changelog","description":"Release notes for the Punjab Educare Android app, listed in reverse chronological order.","prev":false,"next":false},"headers":[],"relativePath":"punjab-educare/changelogs/android.md","filePath":"punjab-educare/changelogs/android.md","lastUpdated":1772245652000}'),n={name:"punjab-educare/changelogs/android.md"};function r(o,e,s,d,h,c){return a(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="android-app-changelog" tabindex="-1">Android App Changelog <a class="header-anchor" href="#android-app-changelog" aria-label="Permalink to “Android App Changelog”">​</a></h1><h2 id="v6" tabindex="-1">v6 <a class="header-anchor" href="#v6" aria-label="Permalink to “v6”">​</a></h2><h3 id="v6-13-8" tabindex="-1">v6.13.8 <a class="header-anchor" href="#v6-13-8" aria-label="Permalink to “v6.13.8”">​</a></h3><p><strong>2025-10-16 10:56</strong></p><ul><li>Bug fixes.</li><li>Fixed the issue where options were not displayed for teacher created quizzes.</li><li>Added option for start and end times for quizzes created by teachers.</li></ul><h3 id="v6-13-9" tabindex="-1">v6.13.9 <a class="header-anchor" href="#v6-13-9" aria-label="Permalink to “v6.13.9”">​</a></h3><p><strong>2025-10-09 23:20</strong></p><ul><li>Bug fixes.</li><li>App is now fully translated to Hindi.</li><li>Added feedback option to report: <ul><li>Any missing / outdated content</li><li>Any issue or error with the app</li><li>Give a review on how the app is functioning</li><li>Suggest new features or improvements</li></ul></li></ul><h3 id="v6-13-7" tabindex="-1">v6.13.7 <a class="header-anchor" href="#v6-13-7" aria-label="Permalink to “v6.13.7”">​</a></h3><p><strong>2025-10-09 08:45</strong></p><ul><li>Quiz features are now live for teachers: <ul><li>Upload class list for students.</li><li>Create quiz for available topics from 30000+ questions bank.</li><li>Check quiz result for class and student performance.</li></ul></li><li>Student login is available after uploading class list for the students.</li></ul><h3 id="v6-13-4" tabindex="-1">v6.13.4 <a class="header-anchor" href="#v6-13-4" aria-label="Permalink to “v6.13.4”">​</a></h3><p><strong>2025-09-21 09:14</strong></p><ul><li>Bug fixes.</li><li>Improved app help section.</li><li>Student login is available for selected classes.</li></ul><h3 id="v6-13-1" tabindex="-1">v6.13.1 <a class="header-anchor" href="#v6-13-1" aria-label="Permalink to “v6.13.1”">​</a></h3><p><strong>2025-09-11 22:45</strong></p><ul><li>Added questions UUID for reporting any issues with questions.</li><li>Added certificate styles for student certificates.</li></ul><h3 id="v6-13-0" tabindex="-1">v6.13.0 <a class="header-anchor" href="#v6-13-0" aria-label="Permalink to “v6.13.0”">​</a></h3><p><strong>2025-09-11 02:30</strong></p><ul><li>Bug fixes and optimized the app for faster performance.</li><li>Fixed app crashing for some devices.</li></ul><h3 id="v6-12-22" tabindex="-1">v6.12.22 <a class="header-anchor" href="#v6-12-22" aria-label="Permalink to “v6.12.22”">​</a></h3><p><strong>2025-09-10 02:44</strong></p><ul><li>Added Practice Quiz functionality for students and right in time for the exams.</li><li>App now supports full light and dark modes.</li><li>Added teacher specific functions to register and contribute questions for the quiz.</li></ul><h3 id="v6-12-21" tabindex="-1">v6.12.21 <a class="header-anchor" href="#v6-12-21" aria-label="Permalink to “v6.12.21”">​</a></h3><p><strong>2025-09-09 00:05</strong></p><ul><li>Added Practice Quiz functionality for students and right in time for the exams.</li><li>App now supports full light and dark modes.</li><li>Added teacher specific functions to register and contribute questions for the quiz.</li></ul><h3 id="v6-11-3" tabindex="-1">v6.11.3 <a class="header-anchor" href="#v6-11-3" aria-label="Permalink to “v6.11.3”">​</a></h3><p><strong>2025-08-03 07:09</strong></p><ul><li>Improved Quiz Attempt functionality: <ul><li>Added placeholder if no quiz available.</li><li>Added support for multiline question and answer.</li><li>Fixed the issue where multiple languages were mixing for the quiz questions.</li><li>Added ability to skip question to perform at last.</li></ul></li></ul><h3 id="v6-11-2" tabindex="-1">v6.11.2 <a class="header-anchor" href="#v6-11-2" aria-label="Permalink to “v6.11.2”">​</a></h3><p><strong>2025-08-03 00:04</strong></p><ul><li>Added quiz attempt functionality for students: <ul><li>Selection between 10 or 20 questions for the quiz.</li><li>Quiz timer (30 seconds for each question).</li><li>Certificate award after finish.</li><li>Ability to save certificate to gallery or share.</li></ul></li><li>Added quiz manager: <ul><li>Upload questions to quiz.</li><li>Edit quiz questions contributor details.</li></ul></li><li>Added questions bank to display all questions.</li></ul><h3 id="v6-11-1" tabindex="-1">v6.11.1 <a class="header-anchor" href="#v6-11-1" aria-label="Permalink to “v6.11.1”">​</a></h3><p><strong>2025-07-26 23:49</strong></p><ul><li>Fixed the notifications deleting issue.</li><li>Added admin page to manage admins.</li></ul><h3 id="v6-11" tabindex="-1">v6.11 <a class="header-anchor" href="#v6-11" aria-label="Permalink to “v6.11”">​</a></h3><p><strong>2025-07-26 01:42</strong></p><ul><li>Moved the app from Firebase to private API.</li></ul><h3 id="v6-10-2" tabindex="-1">v6.10.2 <a class="header-anchor" href="#v6-10-2" aria-label="Permalink to “v6.10.2”">​</a></h3><p><strong>2025-07-11 16:21</strong></p><ul><li>Fixed the issue where the new greeting for the next day kept showing repetitively.</li></ul><h3 id="v6-10-1" tabindex="-1">v6.10.1 <a class="header-anchor" href="#v6-10-1" aria-label="Permalink to “v6.10.1”">​</a></h3><p><strong>2025-07-11 00:14</strong></p><ul><li>Fixed greeting screen where some users reported it was being displayed every time the app was opened.</li></ul><h3 id="v6-10" tabindex="-1">v6.10 <a class="header-anchor" href="#v6-10" aria-label="Permalink to “v6.10”">​</a></h3><p><strong>2025-07-09 00:49</strong></p><ul><li>Added ability to recognize and open links in external browser.</li><li>Added formatting options for notifications (subheadings, bold, italics, strike-through, underline).</li><li>The greeting is only shown once per day (if the greeting content or image changes, it will be shown again the same day).</li></ul><h3 id="v6-9" tabindex="-1">v6.9 <a class="header-anchor" href="#v6-9" aria-label="Permalink to “v6.9”">​</a></h3><p><strong>2025-07-07 22:06</strong></p><ul><li>Greeting screen downloads the content then shows so there is no loading after the greeting is shown.</li><li>Added notification counter for people who read the notification.</li></ul><h3 id="v6-8" tabindex="-1">v6.8 <a class="header-anchor" href="#v6-8" aria-label="Permalink to “v6.8”">​</a></h3><p><strong>2025-07-06 23:45</strong></p><ul><li>Notification manager and greetings manager moved to new App Management view.</li><li>Added app icons.</li><li>App drawer UI improved.</li><li>Changed app version to v6.</li></ul><h3 id="v6-7" tabindex="-1">v6.7 <a class="header-anchor" href="#v6-7" aria-label="Permalink to “v6.7”">​</a></h3><p><strong>2025-07-05 22:07</strong></p><ul><li>Added Greetings screen to app start.</li><li>Added greetings manager for admin access.</li><li>Add new greeting and change existing ones from within the app.</li></ul><h3 id="v6-6" tabindex="-1">v6.6 <a class="header-anchor" href="#v6-6" aria-label="Permalink to “v6.6”">​</a></h3><p><strong>2025-07-05 02:57</strong></p><ul><li>Updated Notification Manager screen.</li><li>Added functionality to notification manager to delete notification from Firebase database.</li><li>Added functionality to resend notification.</li><li>Added helper cards to various screens explaining the functionality.</li><li>Improved app slider menu UI and functionality.</li></ul><h3 id="v6-5" tabindex="-1">v6.5 <a class="header-anchor" href="#v6-5" aria-label="Permalink to “v6.5”">​</a></h3><p><strong>2025-07-03 23:44</strong></p><ul><li>Added ability to delete a single download.</li><li>Notifications reordered to display latest on top.</li><li>Notification list now only shows the title of notifications and up to 2 lines of message.</li><li>Tap on notification to show the full message content.</li><li>Login to admin panel using Google Account.</li><li>Send notifications from app.</li></ul><h3 id="v6-4" tabindex="-1">v6.4 <a class="header-anchor" href="#v6-4" aria-label="Permalink to “v6.4”">​</a></h3><p><strong>2025-07-03 03:29</strong></p><ul><li>Tapping on navigation bar tabs again when on same screen will reload screen to base site.</li><li>Implemented notifications inside app from Firebase.</li><li>Updated file download messages.</li><li>Updated UI and functionality of downloads screen.</li><li>Notification bell icon added to home screen app bar.</li></ul><h3 id="v6-3" tabindex="-1">v6.3 <a class="header-anchor" href="#v6-3" aria-label="Permalink to “v6.3”">​</a></h3><p><strong>2025-07-02 02:25</strong></p><ul><li>Changed YouTube links to open outside the app.</li><li>Fixed Google Drive downloads.</li><li>Download and keep the files inside the app.</li><li>Added Downloads screen to manage the downloads.</li></ul><div class="tip custom-block"><p class="custom-block-title">Notes (pre-v6)</p><p>This app was originally developed and maintained by someone else.<br> Release notes before v6 are limited to Google Play history summaries.</p></div><h2 id="v5" tabindex="-1">v5 <a class="header-anchor" href="#v5" aria-label="Permalink to “v5”">​</a></h2><h3 id="v5-1" tabindex="-1">v5.1 <a class="header-anchor" href="#v5-1" aria-label="Permalink to “v5.1”">​</a></h3><p><strong>2025-01-24 21:47</strong></p><ul><li>Bug fixes and feature enhancements.</li></ul><h2 id="v4" tabindex="-1">v4 <a class="header-anchor" href="#v4" aria-label="Permalink to “v4”">​</a></h2><h3 id="v4-1" tabindex="-1">v4.1 <a class="header-anchor" href="#v4-1" aria-label="Permalink to “v4.1”">​</a></h3><p><strong>2021-09-21 13:32</strong></p><ul><li>Feature enhancements.</li></ul><h2 id="v3" tabindex="-1">v3 <a class="header-anchor" href="#v3" aria-label="Permalink to “v3”">​</a></h2><h3 id="v3-1" tabindex="-1">v3.1 <a class="header-anchor" href="#v3-1" aria-label="Permalink to “v3.1”">​</a></h3><p><strong>2021-04-13 08:04</strong></p><ul><li>Several improvements.</li></ul><h2 id="v1" tabindex="-1">v1 <a class="header-anchor" href="#v1" aria-label="Permalink to “v1”">​</a></h2><h3 id="v1-2" tabindex="-1">v1.2 <a class="header-anchor" href="#v1-2" aria-label="Permalink to “v1.2”">​</a></h3><p><strong>2020-07-22 14:10</strong></p><ul><li>Bug fixes.</li></ul><h3 id="v1-1" tabindex="-1">v1 <a class="header-anchor" href="#v1-1" aria-label="Permalink to “v1”">​</a></h3><p><strong>2020-07-09 23:04</strong></p><ul><li>First release.</li></ul>',88)])])}const v=i(n,[["render",r]]);export{u as __pageData,v as default};
